Функция ПолучитьСальдоСчета(Счет) Экспорт
	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	ЕСТЬNULL(СУММА(Обороты.СуммаОборотДт), 0) КАК Дт,
	|	ЕСТЬNULL(СУММА(Обороты.СуммаОборотКт), 0) КАК Кт
	|ИЗ
	|	РегистрБухгалтерии.Хозрасчетный.Обороты(, , , Счет В ИЕРАРХИИ(&Счет), , ) КАК Обороты";
	Запрос.УстановитьПараметр("Счет", Счет);
	Выборка = Запрос.Выполнить().Выбрать();
	Выборка.Следующий();
	Дт = Выборка.Дт;
	Кт = Выборка.Кт;
	Если Счет.Вид = ВидСчета.Пассивный Тогда
		Возврат Кт - Дт;
	Иначе
		Возврат Дт - Кт;
	КонецЕсли;
КонецФункции
